async function runRepairStatement(statement: string) {
  try {
    await prisma.$executeRawUnsafe(statement);
  } catch {
    // Fire-and-forget by design. Schema repair must never break requests or startup.
  }
}

async function runAllSchemaRepairsOnce() {
  if (schemaRepairCompleted) {
    return;
  }

  if (!schemaRepairInFlight) {
    schemaRepairInFlight = (async () => {
      try {
        for (const repair of REPAIRS) {
          await executeAlwaysOnSchemaRepair(repair.key, repair.statements);
        }
      } finally {
        schemaRepairCompleted = true;
      }
    })();
  }

  await schemaRepairInFlight;
}

async function executeAlwaysOnSchemaRepair(_key: string, statements: string[]) {
  if (schemaRepairCompleted) return;

  for (const statement of statements) {
    await runRepairStatement(statement);
  }
}

export async function ensureStoreSettingsStorage() {
  if (schemaRepairCompleted) return;
  await runAllSchemaRepairsOnce();
}

